def find_key(secret):
    key = ""
    for i in range(len(secret)):
        if ord(secret[i]) >= 97 and ord(secret[i]) <= 122:
            key += chr(ord(secret[i]) + 13)
        else:
            key += chr(ord(secret[i]) - 13)
    return key
